export const BANK_LIST = Object.values(BANK)

export function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
}

export function resolveBank(input) {
  if (!input) return null
  const trimmed = String(input).trim()
  const direct = BANK[slugify(trimmed)]
  if (direct) return direct
  for (const token of trimmed.split(/[\/|,]/)) {
    const m = BANK[slugify(token)]
    if (m) return m
  }
  return null
}
